import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as s,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Yandex Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/yandex.md","filePath":"ta/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"ta/upload/yandex.md"};function p(c,e,h,u,m,x){return s(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="yandex-channel-சேர்க்கவும்" tabindex="-1">Yandex Channel சேர்க்கவும் <a class="header-anchor" href="#yandex-channel-சேர்க்கவும்" aria-label="Permalink to &quot;Yandex Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="முதலில்-தேவையானவை" tabindex="-1">முதலில் தேவையானவை <a class="header-anchor" href="#முதலில்-தேவையானவை" aria-label="Permalink to &quot;முதலில் தேவையானவை&quot;">​</a></h2><table tabindex="0"><thead><tr><th>தேவை</th><th>ஏன் தேவை</th></tr></thead><tbody><tr><td>Yandex account</td><td>sign in செய்து Yandex Disk authorize செய்ய</td></tr><tr><td>Yandex OAuth app</td><td><code>Client ID</code> மற்றும் <code>Client Secret</code> உருவாக்க</td></tr><tr><td>உங்கள் ImgBed domain</td><td>OAuth redirect URI-க்கு</td></tr><tr><td>கிடைக்கும் Yandex Disk storage</td><td>உண்மையான file storage location ஆக</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-yandex-oauth-app-உருவாக்கவும்" tabindex="-1">Step 1: Yandex OAuth App உருவாக்கவும் <a class="header-anchor" href="#step-1-yandex-oauth-app-உருவாக்கவும்" aria-label="Permalink to &quot;Step 1: Yandex OAuth App உருவாக்கவும்&quot;">​</a></h3><ol><li>Yandex OAuth app creation page திறக்கவும்:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>sign in page-க்கு redirect ஆனால் முதலில் Yandex account-ல் sign in செய்யவும்.</li><li>புதிய app உருவாக்கவும்.</li><li>app-க்கு அறியக்கூடிய பெயர் கொடுக்கவும், உதா. <code>imgbed-yandex</code>.</li><li>callback அல்லது redirect URL settings கண்டறியவும்.</li><li>உள்ளிடவும்:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="step-2-permissions-confirm-செய்யவும்" tabindex="-1">Step 2: Permissions Confirm செய்யவும் <a class="header-anchor" href="#step-2-permissions-confirm-செய்யவும்" aria-label="Permalink to &quot;Step 2: Permissions Confirm செய்யவும்&quot;">​</a></h3><p>தற்போதைய ImgBed Yandex integration-க்கு <code>Yandex.Disk REST API</code> கீழ் இந்த permissions வேண்டும்:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>ImgBed app folder-ல் files சேமிக்க அனுமதி</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>files மற்றும் download links படிக்கும்</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>files upload, folders create, files delete செய்யும்</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>disk quota மற்றும் used space படிக்கும்</td></tr></tbody></table><p><code>Yandex ID API</code> கீழ் இவை தெரிந்தால் optional:</p><table tabindex="0"><thead><tr><th>Permission Text</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Optional</td></tr><tr><td><code>Access to email address</code></td><td>Optional</td></tr></tbody></table><p>core upload, download, deletion, quota features மேலே உள்ள நான்கு <code>Yandex.Disk REST API</code> permissions-ஐ சார்ந்தவை.</p><p><img src="'+t+'" alt="Configure Yandex Disk permissions" loading="lazy"></p><h3 id="step-3-app-credentials-copy-செய்யவும்" tabindex="-1">Step 3: App Credentials Copy செய்யவும் <a class="header-anchor" href="#step-3-app-credentials-copy-செய்யவும்" aria-label="Permalink to &quot;Step 3: App Credentials Copy செய்யவும்&quot;">​</a></h3><p>app உருவான பிறகு:</p><table tabindex="0"><thead><tr><th>Yandex Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Record Client ID and Secret" loading="lazy"></p><h3 id="step-4-imgbed-ல்-yandex-channel-நிரப்பவும்" tabindex="-1">Step 4: ImgBed-ல் Yandex Channel நிரப்பவும் <a class="header-anchor" href="#step-4-imgbed-ல்-yandex-channel-நிரப்பவும்" aria-label="Permalink to &quot;Step 4: ImgBed-ல் Yandex Channel நிரப்பவும்&quot;">​</a></h3><p>Upload Settings-ல் <code>Yandex</code> தேர்வு செய்து:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>அறியக்கூடிய பெயர், உதா. <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>Yandex app <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>Yandex app <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>இப்போது காலியாக விடவும்</td></tr><tr><td>Root directory</td><td>Optional. default <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+d+'" alt="Edit channel config" loading="lazy"></p><h3 id="step-5-refresh-token-பெறவும்" tabindex="-1">Step 5: Refresh Token பெறவும் <a class="header-anchor" href="#step-5-refresh-token-பெறவும்" aria-label="Permalink to &quot;Step 5: Refresh Token பெறவும்&quot;">​</a></h3><ol><li>ImgBed-ல் <code>Get Token</code> கிளிக் செய்யவும்.</li><li>connect செய்ய வேண்டிய Yandex account-ல் sign in செய்யவும்.</li><li>authorization prompt approve செய்யவும்.</li><li>callback page <code>Refresh Token</code> காட்டும்.</li><li>அதை copy செய்யவும்.</li><li>ImgBed-க்கு திரும்பி <code>Refresh Token</code> field-ல் paste செய்யவும்.</li></ol><p><img src="'+n+`" alt="Copy refresh token after authorization" loading="lazy"></p><h3 id="step-6-channel-save-செய்யவும்" tabindex="-1">Step 6: Channel Save செய்யவும் <a class="header-anchor" href="#step-6-channel-save-செய்யவும்" aria-label="Permalink to &quot;Step 6: Channel Save செய்யவும்&quot;">​</a></h3><p>அனைத்து fields நிரப்பிய பிறகு channel save செய்யவும்.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Yandex OAuth Console திறக்கவும்</span></span>
<span class="line"><span>-&gt; app உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/yandex/callback சேர்க்கவும்</span></span>
<span class="line"><span>-&gt; Yandex Disk permissions confirm செய்யவும்</span></span>
<span class="line"><span>-&gt; Client ID மற்றும் Client Secret copy செய்யவும்</span></span>
<span class="line"><span>-&gt; ImgBed-ல் Client ID / Client Secret நிரப்பவும்</span></span>
<span class="line"><span>-&gt; Get Token கிளிக் செய்யவும்</span></span>
<span class="line"><span>-&gt; callback page-ல் இருந்து Refresh Token copy செய்யவும்</span></span>
<span class="line"><span>-&gt; ImgBed-ல் paste செய்து save செய்யவும்</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const k=o(r,[["render",p]]);export{f as __pageData,k as default};
